Page._content:
/*
 * 全站视觉变量：页脚使用独立背景，不再和页面主背景混在一起。
 */
:root {
    --footer-bg-start: rgba(22, 34, 54, 0.92);
    --footer-bg-end: rgba(40, 60, 92, 0.9);
    --footer-text-color: #f6f8ff;
    --footer-muted-color: rgba(246, 248, 255, 0.82);
}

/* 保留头图区透明效果 */
#page-header {
    background-color: transparent;
}

/* 页脚独立背景与层次 */
#footer {
    position: relative;
    overflow: hidden;
    margin-top: 2.25rem;
    background: linear-gradient(125deg, var(--footer-bg-start), var(--footer-bg-end)) !important;
    box-shadow: 0 -10px 30px rgba(10, 20, 36, 0.22);
}

#footer::before {
    content: "";
    position: absolute;
    inset: 0;
    background:
        radial-gradient(circle at 15% 18%, rgba(255, 255, 255, 0.16), transparent 34%),
        radial-gradient(circle at 80% 72%, rgba(120, 180, 255, 0.22), transparent 42%);
    pointer-events: none;
}

#footer .footer-other {
    position: relative;
    z-index: 1;
    color: var(--footer-text-color);
}

#footer .copyright,
#footer .footer_custom_text,
#footer #workboard,
#footer #ghbdages {
    color: var(--footer-muted-color) !important;
}

#footer a {
    color: #ffffff !important;
}

/* 兼容 footer_beautify 注入后的徽章间距 */
#footer #ghbdages {
    margin: 0.6rem auto 0;
    text-align: center;
}

/* 头像呼吸灯 */
[data-theme="light"] .avatar-img {
  animation: huxi_light 4s ease-in-out infinite;
}

[data-theme="dark"] .avatar-img {
  animation: huxi_dark 4s ease-in-out infinite;
}

@keyframes huxi_light {
  0% {
    box-shadow: 0 0 1px 1px #e9f5fa;
  }
  50% {
    box-shadow: 0 0 5px 5px #e9f5fa;
  }
  100% {
    box-shadow: 0 0 1px 1px #e9f5fa;
  }
}

@keyframes huxi_dark {
  0% {
    box-shadow: 0 0 1px 1px #39c5bb;
  }
  50% {
    box-shadow: 0 0 5px 5px #39c5bb;
  }
  100% {
    box-shadow: 0 0 1px 1px #39c5bb;
  }
}

/* 文章页顶波浪线 */
.main-hero-waves-area {
  width: 100%;
  position: absolute;
  left: 0;
  bottom: -11px;
  z-index: 5;
}

.waves-area .waves-svg {
  width: 100%;
  height: 5rem;
}

.parallax > use {
  animation: move-forever 25s cubic-bezier(0.55, 0.5, 0.45, 0.5) infinite;
}

.parallax > use:nth-child(1) {
  animation-delay: -2s;
  animation-duration: 7s;
  fill: #f7f9febd;
}

.parallax > use:nth-child(2) {
  animation-delay: -3s;
  animation-duration: 10s;
  fill: #f7f9fe82;
}

.parallax > use:nth-child(3) {
  animation-delay: -4s;
  animation-duration: 13s;
  fill: #f7f9fe36;
}

.parallax > use:nth-child(4) {
  animation-delay: -5s;
  animation-duration: 20s;
  fill: #f7f9fe;
}

[data-theme="dark"] .parallax > use:nth-child(1) {
  animation-delay: -2s;
  animation-duration: 7s;
  fill: #18171dc8;
}

[data-theme="dark"] .parallax > use:nth-child(2) {
  animation-delay: -3s;
  animation-duration: 10s;
  fill: #18171d80;
}

[data-theme="dark"] .parallax > use:nth-child(3) {
  animation-delay: -4s;
  animation-duration: 13s;
  fill: #18171d3e;
}

[data-theme="dark"] .parallax > use:nth-child(4) {
  animation-delay: -5s;
  animation-duration: 20s;
  fill: #18171d;
}

@keyframes move-forever {
  0% {
    transform: translate3d(-90px, 0, 0);
  }
  100% {
    transform: translate3d(85px, 0, 0);
  }
}

@media (max-width: 768px) {
  .waves-area .waves-svg {
    height: 40px;
    min-height: 40px;
  }
}

/* 作者卡片按钮小车动画（不依赖额外动画库） */
#card-info-btn .author-car-icon {
  margin-left: 12px;
  display: inline-block;
  vertical-align: middle;
  font-size: 1.28em;
  line-height: 1;
  position: relative;
  --car-run-distance: clamp(78px, 18vw, 145px);
  animation: author_car_drive 2.1s linear infinite;
  transform-origin: center bottom;
  opacity: 1;
  will-change: transform;
}

#rightside .iconfont {
  margin-right: 0;
}

@keyframes author_car_drive {
  0% {
    transform: translateX(0) translateY(0) rotate(0deg);
    opacity: 1;
  }
  18% {
    transform: translateX(calc(var(--car-run-distance) * 0.24)) translateY(-1px) rotate(-2deg);
    opacity: 1;
  }
  36% {
    transform: translateX(calc(var(--car-run-distance) * 0.48)) translateY(0) rotate(1deg);
    opacity: 1;
  }
  54% {
    transform: translateX(calc(var(--car-run-distance) * 0.72)) translateY(-1px) rotate(-1deg);
    opacity: 1;
  }
  68% {
    transform: translateX(var(--car-run-distance)) translateY(0) rotate(0deg);
    opacity: 1;
  }
  78% {
    transform: translateX(calc(var(--car-run-distance) + 14px)) translateY(-1px) rotate(2deg);
    opacity: 0;
  }
  79% {
    transform: translateX(-20px) translateY(0) rotate(0deg);
    opacity: 0;
  }
  100% {
    transform: translateX(0) translateY(0) rotate(0deg);
    opacity: 1;
  }
}

/* 白天/黑夜模式都保持页面主背景无额外遮罩 */
#web_bg:before {
    background-color: rgba(255, 255, 255, 0) !important;
}

[data-theme="dark"] #web_bg:before {
    background-color: rgba(0, 0, 0, 0) !important;
}

/* 留言板页面与页脚留出安全间距，避免视觉挤压 */
#maincontent {
    margin-bottom: 3.2rem;
}

/* 修复移动端 violet 留言板固定宽度导致的溢出与排版错位 */
@media screen and (max-width: 600px) {
    #maincontent {
        width: calc(100vw - 24px) !important;
        margin: 12px auto 2.8rem !important;
    }

    #form-wrap,
    #envelope {
        width: 100% !important;
        max-width: 100% !important;
    }

    #form-wrap,
    #form-wrap:hover {
        height: auto !important;
        top: 0 !important;
    }

    #envelope {
        padding-top: 22vw !important;
    }

    .formmain {
        width: 100% !important;
    }
}

@font-face {
  font-family: 'YSHST';
  src: url('/font/YOUSHEhaoshenti.woff2');
  font-weight: normal;
  font-style: normal;
  font-display: swap;
}

/* ====================================== */
/* 导航栏居中 + 横向子菜单 魔改（店长同款） */
/* ====================================== */

/* 一级菜单居中 */
#nav .menus_items {
  position: absolute !important;
  width: fit-content !important;
  left: 50% !important;
  transform: translateX(-50%) !important;
}

/* 子菜单横向展示 */
#nav .menus_items .menus_item:hover .menus_item_child {
  display: flex !important;
}

/* 子菜单居中修正（适配大多数导航）*/
.menus_item_child {
  left: 50% !important;
  transform: translateX(-50%) !important;
}

/* 隐藏导航栏搜索按钮文字（只留图标）*/
#search-button span {
  display: none !important;
}

/* ====================================== */
/* 黑夜霓虹灯 2.0（纯CSS · 店长同款） */
/* ====================================== */

/* 日间模式不生效 */
[data-theme="light"] #site-name,
[data-theme="light"] #site-title,
[data-theme="light"] #site-subtitle,
[data-theme="light"] #post-info {
  animation: none;
}
/* 夜间模式生效 */
[data-theme="dark"] #site-name,
[data-theme="dark"] #site-title {
  animation: light_15px 10s linear infinite;
}
[data-theme="dark"] #site-subtitle {
  animation: light_10px 10s linear infinite;
}
[data-theme="dark"] #post-info {
  animation: light_5px 10s linear infinite;
}
/* 关键帧描述 */
@keyframes light_15px {
  0% {
    text-shadow: #5636ed 0 0 15px;
  }
  12.5% {
    text-shadow: #11ee5e 0 0 15px;
  }
  25% {
    text-shadow: #f14747 0 0 15px;
  }
  37.5% {
    text-shadow: #f1a247 0 0 15px;
  }
  50% {
    text-shadow: #f1ee47 0 0 15px;
  }
  62.5% {
    text-shadow: #b347f1 0 0 15px;
  }
  75% {
    text-shadow: #002afa 0 0 15px;
  }
  87.5% {
    text-shadow: #ed709b 0 0 15px;
  }
  100% {
    text-shadow: #39c5bb 0 0 15px;
  }
}
@keyframes light_10px {
  0% { text-shadow: #5636ed 0 0 10px; }
  12.5% { text-shadow: #11ee5e 0 0 10px; }
  25% { text-shadow: #f14747 0 0 10px; }
  37.5% { text-shadow: #f1a247 0 0 10px; }
  50% { text-shadow: #f1ee47 0 0 10px; }
  62.5% { text-shadow: #b347f1 0 0 10px; }
  75% { text-shadow: #002afa 0 0 10px; }
  87.5% { text-shadow: #ed709b 0 0 10px; }
  100% { text-shadow: #39c5bb 0 0 10px; }
}
@keyframes light_5px {
  0% { text-shadow: #5636ed 0 0 5px; }
  12.5% { text-shadow: #11ee5e 0 0 5px; }
  25% { text-shadow: #f14747 0 0 5px; }
  37.5% { text-shadow: #f1a247 0 0 5px; }
  50% { text-shadow: #f1ee47 0 0 5px; }
  62.5% { text-shadow: #b347f1 0 0 5px; }
  75% { text-shadow: #002afa 0 0 5px; }
  87.5% { text-shadow: #ed709b 0 0 5px; }
  100% { text-shadow: #39c5bb 0 0 5px; }
}

/* 个人信息卡片背景图（替代渐变色卡片） */
[data-theme="light"] #aside-content > .card-widget.card-info,
[data-theme="dark"] #aside-content > .card-widget.card-info {
  background-image:
    linear-gradient(to bottom, rgba(255, 255, 255, 0.08) 45%, rgba(255, 255, 255, 0.92) 100%),
    url(/img/back3.jpg);
  background-repeat: no-repeat;
  background-attachment: inherit;
  background-size: 100% auto;
  background-position: top center;
  border: none !important;
}

/* 可选优化：卡片内文字/图标配色适配，避免渐变背景导致文字看不清 */
#aside-content .card-info .info-content > div,
#aside-content .card-info .author-info__name,
#aside-content .card-info .author-info__description,
#aside-content .card-info .card-info-data > .item,
#aside-content .card-info .card-info-social > a {
  color: #333 !important; /* 日间模式文字深色调，保证可读性 */
}
[data-theme="dark"] #aside-content .card-info .info-content > div,
[data-theme="dark"] #aside-content .card-info .author-info__name,
[data-theme="dark"] #aside-content .card-info .author-info__description,
[data-theme="dark"] #aside-content .card-info .card-info-data > .item,
[data-theme="dark"] #aside-content .card-info .card-info-social > a {
  color: #f5f5f5 !important; /* 夜间模式文字浅色调，保证可读性 */
}
/* 强制全站使用自定义字体 */
body, .site-name, #site-title {
  font-family: 'YSHST', -apple-system, BlinkMacSystemFont, "Segoe UI", "Helvetica Neue", Lato, Roboto, "PingFang SC", "Microsoft JhengHei", "Microsoft YaHei", sans-serif !important;
}

/* Iconfont 彩色图标样式 */
.iconfont {
  font-family: "iconfont" !important;
  font-size: 1.2em;
  font-style: normal;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  vertical-align: middle;
  margin-right: 4px;
}

/* ====================================== */
/* SVG 动态彩色图标（菜单栏 & 社交栏通用） */
/* ====================================== */
svg.icon,
svg.menu_icon {
  width: 1.28em;
  height: 1.28em;
  vertical-align: -0.15em;
  fill: currentColor;
  overflow: hidden;
}/* ================================ */
/* 博客全局样式美化：毛玻璃亚克力风格 */
/* ================================ */
:root {
  --trans-light: rgba(255, 255, 255, 0.88);
  --trans-dark: rgba(25, 25, 25, 0.88);
  --border-style: 1px solid rgb(169, 169, 169);
  --backdrop-filter: blur(5px) saturate(150%);
}

/* 首页文章卡片 */
#recent-posts > .recent-post-item {
  background: var(--trans-light);
  backdrop-filter: var(--backdrop-filter);
  border-radius: 25px;
  border: var(--border-style);
}

/* 侧边栏卡片 */
#aside-content .card-widget {
  background: var(--trans-light);
  backdrop-filter: var(--backdrop-filter);
  border-radius: 18px;
  border: var(--border-style);
}

/* 文章页、归档、单页面 */
div#post,
div#page,
div#archive {
  background: var(--trans-light);
  backdrop-filter: var(--backdrop-filter);
  border: var(--border-style);
  border-radius: 20px;
}

/* 哔哩哔哩视频适配 */
.aspect-ratio {
  position: relative;
  width: 90%;
  height: auto;
  padding-bottom: 75%;
  margin: 3% auto;
  text-align: center;
}

.aspect-ratio iframe {
  position: absolute;
  width: 100%;
  height: 86%;
  left: 0;
  top: 0;
}

/* 导航栏 */
#page-header.nav-fixed #nav {
  background: rgba(255, 255, 255, 0.75);
  backdrop-filter: var(--backdrop-filter);
}

[data-theme="dark"] #page-header.nav-fixed #nav {
  background: rgba(0, 0, 0, 0.7) !important;
}

/* 夜间模式 */
[data-theme="dark"] #recent-posts > .recent-post-item,
[data-theme="dark"] #aside-content .card-widget,
[data-theme="dark"] div#post,
[data-theme="dark"] div#archive,
[data-theme="dark"] div#page {
  background: var(--trans-dark);
}

/* 夜间模式遮罩去掉 */
[data-theme="dark"] #footer::before,
[data-theme="dark"] #page-header::before {
  background: transparent !important;
}

/* 阅读模式 */
.read-mode #aside-content .card-widget {
  background: rgba(158, 204, 171, 0.5) !important;
}
.read-mode div#post {
  background: rgba(158, 204, 171, 0.5) !important;
}

/* 夜间模式阅读模式 */
[data-theme="dark"] .read-mode #aside-content .card-widget,
[data-theme="dark"] .read-mode div#post {
  background: rgba(25, 25, 25, 0.9) !important;
  color: #ffffff;
}

/* ====================================== */
/* 宽屏适配 + 仅首页显示侧边栏（自用） */
/* ====================================== */

/* 全局宽度 */
.layout {
  max-width: 1400px;
}

/* 侧边卡片栏宽度 */
.aside-content {
  max-width: 318px;
  min-width: 300px;
}

/* 平板尺寸自适应 */
@media screen and (max-width: 900px) {
  .aside-content {
    max-width: none !important;
    min-width: 0 !important;
    padding: 0 5px;
  }
}

/* 非首页隐藏侧边栏：利用主题头图 class 区分首页/非首页 */
#body-wrap #page-header.not-home-page + #content-inner .aside-content {
  display: none !important;
}

/* 非首页内容区拉满宽度 */
#body-wrap #page-header.not-home-page + #content-inner #archive,
#body-wrap #page-header.not-home-page + #content-inner #page,
#body-wrap #page-header.not-home-page + #content-inner #category,
#body-wrap #page-header.not-home-page + #content-inner #tag,
#body-wrap #page-header.not-home-page + #content-inner #post {
  width: 100% !important;
}

/* 主页文章三栏（店长思路 + 当前主题结构微调版） */
#body-wrap #page-header.full_page + #content-inner #recent-posts.recent-posts .recent-post-items {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 18px;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts.recent-posts .recent-post-item {
  width: auto !important;
  margin: 0 !important;
  height: 100%;
  display: flex;
  flex-direction: column;
  border-radius: 16px;
  overflow: hidden;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .post_cover {
  width: 100% !important;
  height: 210px;
  margin: 0 !important;
  border-radius: 0;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .post_cover a,
#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .post_cover img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .recent-post-info {
  width: 100% !important;
  display: flex;
  flex-direction: column;
  justify-content: flex-start;
  padding: 14px 16px 16px;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .article-title {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  min-height: 44px;
  margin-bottom: 8px;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .content {
  display: -webkit-box;
  -webkit-line-clamp: 4;
  -webkit-box-orient: vertical;
  overflow: hidden;
  min-height: 88px;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts nav#pagination {
  grid-column: 1 / -1;
}

@media screen and (max-width: 1068px) {
  #body-wrap #page-header.full_page + #content-inner #recent-posts.recent-posts .recent-post-items {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media screen and (max-width: 700px) {
  #body-wrap #page-header.full_page + #content-inner #recent-posts.recent-posts .recent-post-items {
    grid-template-columns: 1fr;
  }

  #body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .post_cover {
    height: 200px;
  }
}

/* ====================================== */
/* 动态彩色图标（店长同款） */
/* ====================================== */
svg.menu_icon {
  width: 1.28em !important;
  height: 1.28em !important;
  vertical-align: -0.15em !important;
  overflow: hidden !important;
  display: inline-block !important;
}

/* ====================================== */
/* 社交彩色图标（店长同款） */
/* ====================================== */
svg.social_icon {
  width: 1.28em !important;
  height: 1.28em !important;
  vertical-align: -0.15em !important;
  overflow: hidden !important;
  display: inline-block !important;
}

/* ====================================== */
/* H1-H6 图标旋转 + 标题缩放（动静结合） */
/* ====================================== */
#content-inner.layout h1,
#content-inner.layout h2,
#content-inner.layout h3,
#content-inner.layout h4,
#content-inner.layout h5,
#content-inner.layout h6 {
  transition: all 0.3s ease;
}

#content-inner.layout h1::before,
#content-inner.layout h2::before,
#content-inner.layout h3::before,
#content-inner.layout h4::before,
#content-inner.layout h5::before,
#content-inner.layout h6::before {
  display: inline-block;
  font-family: "Font Awesome 6 Free";
  font-weight: 900;
  margin-right: 0.25rem;
  animation: heading-icon-rotate 6s linear infinite;
  transition: all 0.3s ease;
  transform-origin: center;
}

/* 旋转动画 */
@keyframes heading-icon-rotate {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

/* 基础样式 */
#content-inner.layout h1::before {
  content: "\f863";
  color: #ef50a8;
  margin-left: -1.55rem;
  font-size: 1.3rem;
  margin-top: -0.23rem;
}

#content-inner.layout h2::before {
  content: "\f863";
  color: #fb7061;
  margin-left: -1.35rem;
  font-size: 1.1rem;
  margin-top: -0.12rem;
}

#content-inner.layout h3::before {
  content: "\f863";
  color: #ffbf00;
  margin-left: -1.22rem;
  font-size: 0.95rem;
  margin-top: -0.09rem;
}

#content-inner.layout h4::before {
  content: "\f863";
  color: #a9e000;
  margin-left: -1.05rem;
  font-size: 0.8rem;
  margin-top: -0.09rem;
}

#content-inner.layout h5::before {
  content: "\f863";
  color: #57c850;
  margin-left: -0.9rem;
  font-size: 0.7rem;
  margin-top: 0;
}

#content-inner.layout h6::before {
  content: "\f863";
  color: #5ec1e0;
  margin-left: -0.9rem;
  font-size: 0.66rem;
  margin-top: 0;
}

/* hover: 图标旋速加快 + 标题轻微放大 + 主题色 */
#content-inner.layout h1:hover::before,
#content-inner.layout h2:hover::before,
#content-inner.layout h3:hover::before,
#content-inner.layout h4:hover::before,
#content-inner.layout h5:hover::before,
#content-inner.layout h6:hover::before {
  color: var(--theme-color);
  animation: heading-icon-rotate 3s linear infinite;
  transform: scale(1.1);
}

#content-inner.layout h1:hover {
  transform: scale(1.03);
}

#content-inner.layout h2:hover,
#content-inner.layout h3:hover {
