/* 文章页顶波浪线 */
.main-hero-waves-area {
  width: 100%;
  position: absolute;
  left: 0;
  bottom: -11px;
  z-index: 5;
}

.waves-area .waves-svg {
  width: 100%;
  height: 5rem;
}

.parallax > use {
  animation: move-forever 25s cubic-bezier(0.55, 0.5, 0.45, 0.5) infinite;
}

.parallax > use:nth-child(1) {
  animation-delay: -2s;
  animation-duration: 7s;
  fill: #f7f9febd;
}

.parallax > use:nth-child(2) {
  animation-delay: -3s;
  animation-duration: 10s;
  fill: #f7f9fe82;
}

.parallax > use:nth-child(3) {
  animation-delay: -4s;
  animation-duration: 13s;
  fill: #f7f9fe36;
}

.parallax > use:nth-child(4) {
  animation-delay: -5s;
  animation-duration: 20s;
  fill: #f7f9fe;
}

[data-theme="dark"] .parallax > use:nth-child(1) {
  animation-delay: -2s;
  animation-duration: 7s;
  fill: #18171dc8;
}

[data-theme="dark"] .parallax > use:nth-child(2) {
  animation-delay: -3s;
  animation-duration: 10s;
  fill: #18171d80;
}

[data-theme="dark"] .parallax > use:nth-child(3) {
  animation-delay: -4s;
  animation-duration: 13s;
  fill: #18171d3e;
}

[data-theme="dark"] .parallax > use:nth-child(4) {
  animation-delay: -5s;
  animation-duration: 20s;
  fill: #18171d;
}

@keyframes move-forever {
  0% {
    transform: translate3d(-90px, 0, 0);
  }
  100% {
    transform: translate3d(85px, 0, 0);
  }
}

@media (max-width: 768px) {
  .waves-area .waves-svg {
    height: 40px;
    min-height: 40px;
  }
}

/* 作者卡片按钮小车动画（不依赖额外动画库） */
#card-info-btn .author-car-icon {
  margin-left: 12px;
  display: inline-block;
  vertical-align: middle;
  font-size: 1.28em;
  line-height: 1;
  position: relative;
  --car-run-distance: clamp(78px, 18vw, 145px);
  animation: author_car_drive 2.1s linear infinite;
  transform-origin: center bottom;
  opacity: 1;
  will-change: transform;
}

#rightside .iconfont {
  margin-right: 0;
}

@keyframes author_car_drive {
  0% {
    transform: translateX(0) translateY(0) rotate(0deg);
    opacity: 1;
  }
  18% {
    transform: translateX(calc(var(--car-run-distance) * 0.24)) translateY(-1px) rotate(-2deg);
    opacity: 1;
  }
  36% {
    transform: translateX(calc(var(--car-run-distance) * 0.48)) translateY(0) rotate(1deg);
    opacity: 1;
  }
  54% {
    transform: translateX(calc(var(--car-run-distance) * 0.72)) translateY(-1px) rotate(-1deg);
    opacity: 1;
  }
  68% {
    transform: translateX(var(--car-run-distance)) translateY(0) rotate(0deg);
    opacity: 1;
  }
  78% {
    transform: translateX(calc(var(--car-run-distance) + 14px)) translateY(-1px) rotate(2deg);
    opacity: 0;
  }
  79% {
    transform: translateX(-20px) translateY(0) rotate(0deg);
    opacity: 0;
  }
  100% {
    transform: translateX(0) translateY(0) rotate(0deg);
    opacity: 1;
  }
}

