/* 黑夜霓虹灯 2.0（纯CSS · 店长同款） */
/* ====================================== */

/* 日间模式不生效 */
[data-theme="light"] #site-name,
[data-theme="light"] #site-title,
[data-theme="light"] #site-subtitle,
[data-theme="light"] #post-info {
  animation: none;
}
/* 夜间模式生效 */
[data-theme="dark"] #site-name,
[data-theme="dark"] #site-title {
  animation: light_15px 10s linear infinite;
}
[data-theme="dark"] #site-subtitle {
  animation: light_10px 10s linear infinite;
}
[data-theme="dark"] #post-info {
  animation: light_5px 10s linear infinite;
}
/* 关键帧描述 */
@keyframes light_15px {
  0% {
    text-shadow: #5636ed 0 0 15px;
  }
  12.5% {
    text-shadow: #11ee5e 0 0 15px;
  }
  25% {
    text-shadow: #f14747 0 0 15px;
  }
  37.5% {
    text-shadow: #f1a247 0 0 15px;
  }
  50% {
    text-shadow: #f1ee47 0 0 15px;
  }
  62.5% {
    text-shadow: #b347f1 0 0 15px;
  }
  75% {
    text-shadow: #002afa 0 0 15px;
  }
  87.5% {
    text-shadow: #ed709b 0 0 15px;
  }
  100% {
    text-shadow: #39c5bb 0 0 15px;
  }
}
@keyframes light_10px {
  0% { text-shadow: #5636ed 0 0 10px; }
  12.5% { text-shadow: #11ee5e 0 0 10px; }
  25% { text-shadow: #f14747 0 0 10px; }
  37.5% { text-shadow: #f1a247 0 0 10px; }
  50% { text-shadow: #f1ee47 0 0 10px; }
  62.5% { text-shadow: #b347f1 0 0 10px; }
  75% { text-shadow: #002afa 0 0 10px; }
  87.5% { text-shadow: #ed709b 0 0 10px; }
  100% { text-shadow: #39c5bb 0 0 10px; }
}
@keyframes light_5px {
  0% { text-shadow: #5636ed 0 0 5px; }
  12.5% { text-shadow: #11ee5e 0 0 5px; }
  25% { text-shadow: #f14747 0 0 5px; }
  37.5% { text-shadow: #f1a247 0 0 5px; }
  50% { text-shadow: #f1ee47 0 0 5px; }
  62.5% { text-shadow: #b347f1 0 0 5px; }
  75% { text-shadow: #002afa 0 0 5px; }
  87.5% { text-shadow: #ed709b 0 0 5px; }
  100% { text-shadow: #39c5bb 0 0 5px; }
}

/* 个人信息卡片背景图（替代渐变色卡片） */
[data-theme="light"] #aside-content > .card-widget.card-info,
[data-theme="dark"] #aside-content > .card-widget.card-info {
  background-image:
    linear-gradient(to bottom, rgba(255, 255, 255, 0.08) 45%, rgba(255, 255, 255, 0.92) 100%),
    url(/img/back3.jpg);
  background-repeat: no-repeat;
  background-attachment: inherit;
  background-size: 100% auto;
  background-position: top center;
  border: none !important;
}

/* 可选优化：卡片内文字/图标配色适配，避免渐变背景导致文字看不清 */
#aside-content .card-info .info-content > div,
#aside-content .card-info .author-info__name,
#aside-content .card-info .author-info__description,
#aside-content .card-info .card-info-data > .item,
#aside-content .card-info .card-info-social > a {
  color: #333 !important; /* 日间模式文字深色调，保证可读性 */
}
[data-theme="dark"] #aside-content .card-info .info-content > div,
[data-theme="dark"] #aside-content .card-info .author-info__name,
[data-theme="dark"] #aside-content .card-info .author-info__description,
[data-theme="dark"] #aside-content .card-info .card-info-data > .item,
[data-theme="dark"] #aside-content .card-info .card-info-social > a {
  color: #f5f5f5 !important; /* 夜间模式文字浅色调，保证可读性 */
}
/* 强制全站使用自定义字体 */
body, .site-name, #site-title {
  font-family: 'YSHST', -apple-system, BlinkMacSystemFont, "Segoe UI", "Helvetica Neue", Lato, Roboto, "PingFang SC", "Microsoft JhengHei", "Microsoft YaHei", sans-serif !important;
}

/* Iconfont 彩色图标样式 */
.iconfont {
  font-family: "iconfont" !important;
  font-size: 1.2em;
  font-style: normal;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  vertical-align: middle;
  margin-right: 4px;
}

/* ====================================== */
/* SVG 动态彩色图标（菜单栏 & 社交栏通用） */
/* ====================================== */
svg.icon,
svg.menu_icon {
  width: 1.28em;
  height: 1.28em;
  vertical-align: -0.15em;
  fill: currentColor;
  overflow: hidden;
}/* ================================ */
/* 博客全局样式美化：毛玻璃亚克力风格 */
/* ================================ */
:root {
  --trans-light: rgba(255, 255, 255, 0.88);
  --trans-dark: rgba(25, 25, 25, 0.88);
  --border-style: 1px solid rgb(169, 169, 169);
  --backdrop-filter: blur(5px) saturate(150%);
}

/* 首页文章卡片 */
#recent-posts > .recent-post-item {
  background: var(--trans-light);
  backdrop-filter: var(--backdrop-filter);
  border-radius: 25px;
  border: var(--border-style);
}

/* 侧边栏卡片 */
#aside-content .card-widget {
  background: var(--trans-light);
  backdrop-filter: var(--backdrop-filter);
  border-radius: 18px;
  border: var(--border-style);
}

/* 文章页、归档、单页面 */
div#post,
div#page,
div#archive {
  background: var(--trans-light);
  backdrop-filter: var(--backdrop-filter);
  border: var(--border-style);
  border-radius: 20px;
}

/* 哔哩哔哩视频适配 */
.aspect-ratio {
  position: relative;
  width: 90%;
  height: auto;
  padding-bottom: 75%;
  margin: 3% auto;
  text-align: center;
}

.aspect-ratio iframe {
  position: absolute;
  width: 100%;
  height: 86%;
  left: 0;
  top: 0;
}

/* 导航栏 */
#page-header.nav-fixed #nav {
  background: rgba(255, 255, 255, 0.75);
  backdrop-filter: var(--backdrop-filter);
}

[data-theme="dark"] #page-header.nav-fixed #nav {
  background: rgba(0, 0, 0, 0.7) !important;
}

/* 夜间模式 */
[data-theme="dark"] #recent-posts > .recent-post-item,
[data-theme="dark"] #aside-content .card-widget,
[data-theme="dark"] div#post,
[data-theme="dark"] div#archive,
[data-theme="dark"] div#page {
  background: var(--trans-dark);
}

/* 夜间模式遮罩去掉 */
[data-theme="dark"] #footer::before,
[data-theme="dark"] #page-header::before {
  background: transparent !important;
}

/* 阅读模式 */
.read-mode #aside-content .card-widget {
  background: rgba(158, 204, 171, 0.5) !important;
}
.read-mode div#post {
  background: rgba(158, 204, 171, 0.5) !important;
}

/* 夜间模式阅读模式 */
[data-theme="dark"] .read-mode #aside-content .card-widget,
[data-theme="dark"] .read-mode div#post {
  background: rgba(25, 25, 25, 0.9) !important;
  color: #ffffff;
}

/* ====================================== */
/* 宽屏适配 + 仅首页显示侧边栏（自用） */
/* ====================================== */

/* 全局宽度 */
.layout {
  max-width: 1400px;
}

/* 侧边卡片栏宽度 */
.aside-content {
  max-width: 318px;
  min-width: 300px;
}

/* 平板尺寸自适应 */
@media screen and (max-width: 900px) {
  .aside-content {
    max-width: none !important;
    min-width: 0 !important;
    padding: 0 5px;
  }
}

/* 非首页隐藏侧边栏：利用主题头图 class 区分首页/非首页 */
#body-wrap #page-header.not-home-page + #content-inner .aside-content {
  display: none !important;
}

/* 非首页内容区拉满宽度 */
#body-wrap #page-header.not-home-page + #content-inner #archive,
#body-wrap #page-header.not-home-page + #content-inner #page,
#body-wrap #page-header.not-home-page + #content-inner #category,
#body-wrap #page-header.not-home-page + #content-inner #tag,
#body-wrap #page-header.not-home-page + #content-inner #post {
  width: 100% !important;
}

/* 主页文章三栏（店长思路 + 当前主题结构微调版） */
#body-wrap #page-header.full_page + #content-inner #recent-posts.recent-posts .recent-post-items {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 18px;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts.recent-posts .recent-post-item {
  width: auto !important;
  margin: 0 !important;
  height: 100%;
  display: flex;
  flex-direction: column;
  border-radius: 16px;
  overflow: hidden;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .post_cover {
  width: 100% !important;
  height: 210px;
  margin: 0 !important;
  border-radius: 0;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .post_cover a,
#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .post_cover img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .recent-post-info {
  width: 100% !important;
  display: flex;
  flex-direction: column;
  justify-content: flex-start;
  padding: 14px 16px 16px;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .article-title {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  min-height: 44px;
  margin-bottom: 8px;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .content {
  display: -webkit-box;
  -webkit-line-clamp: 4;
  -webkit-box-orient: vertical;
  overflow: hidden;
  min-height: 88px;
}

#body-wrap #page-header.full_page + #content-inner #recent-posts nav#pagination {
  grid-column: 1 / -1;
}

@media screen and (max-width: 1068px) {
  #body-wrap #page-header.full_page + #content-inner #recent-posts.recent-posts .recent-post-items {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media screen and (max-width: 700px) {
  #body-wrap #page-header.full_page + #content-inner #recent-posts.recent-posts .recent-post-items {
    grid-template-columns: 1fr;
  }

  #body-wrap #page-header.full_page + #content-inner #recent-posts .recent-post-item .post_cover {
    height: 200px;
  }
}

/* ====================================== */
/* 动态彩色图标（店长同款） */
/* ====================================== */
svg.menu_icon {
  width: 1.28em !important;
  height: 1.28em !important;
  vertical-align: -0.15em !important;
  overflow: hidden !important;
  display: inline-block !important;
}

/* ====================================== */
/* 社交彩色图标（店长同款） */
/* ====================================== */
svg.social_icon {
  width: 1.28em !important;
  height: 1.28em !important;
  vertical-align: -0.15em !important;
  overflow: hidden !important;
  display: inline-block !important;
}

/* ====================================== */
/* H1-H6 图标旋转 + 标题缩放（动静结合） */
/* ====================================== */
#content-inner.layout h1,
#content-inner.layout h2,
#content-inner.layout h3,
#content-inner.layout h4,
#content-inner.layout h5,
#content-inner.layout h6 {
  transition: all 0.3s ease;
}

#content-inner.layout h1::before,
#content-inner.layout h2::before,
#content-inner.layout h3::before,
#content-inner.layout h4::before,
#content-inner.layout h5::before,
#content-inner.layout h6::before {
  display: inline-block;
  font-family: "Font Awesome 6 Free";
  font-weight: 900;
  margin-right: 0.25rem;
  animation: heading-icon-rotate 6s linear infinite;
  transition: all 0.3s ease;
  transform-origin: center;
}

/* 旋转动画 */
@keyframes heading-icon-rotate {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

/* 基础样式 */
#content-inner.layout h1::before {
  content: "\f863";
  color: #ef50a8;
  margin-left: -1.55rem;
  font-size: 1.3rem;
  margin-top: -0.23rem;
}

#content-inner.layout h2::before {
  content: "\f863";
  color: #fb7061;
  margin-left: -1.35rem;
  font-size: 1.1rem;
  margin-top: -0.12rem;
}

#content-inner.layout h3::before {
  content: "\f863";
  color: #ffbf00;
  margin-left: -1.22rem;
  font-size: 0.95rem;
  margin-top: -0.09rem;
}

#content-inner.layout h4::before {
  content: "\f863";
  color: #a9e000;
  margin-left: -1.05rem;
  font-size: 0.8rem;
  margin-top: -0.09rem;
}

#content-inner.layout h5::before {
  content: "\f863";
  color: #57c850;
  margin-left: -0.9rem;
  font-size: 0.7rem;
  margin-top: 0;
}

#content-inner.layout h6::before {
  content: "\f863";
  color: #5ec1e0;
  margin-left: -0.9rem;
  font-size: 0.66rem;
  margin-top: 0;
}

/* hover: 图标旋速加快 + 标题轻微放大 + 主题色 */
#content-inner.layout h1:hover::before,
#content-inner.layout h2:hover::before,
#content-inner.layout h3:hover::before,
#content-inner.layout h4:hover::before,
#content-inner.layout h5:hover::before,
#content-inner.layout h6:hover::before {
  color: var(--theme-color);
  animation: heading-icon-rotate 3s linear infinite;
  transform: scale(1.1);
}

#content-inner.layout h1:hover {
  transform: scale(1.03);
}

#content-inner.layout h2:hover,
#content-inner.layout h3:hover {
  transform: scale(1.02);
}

#content-inner.layout h4:hover,
#content-inner.layout h5:hover,
#content-inner.layout h6:hover {
  transform: scale(1.01);
}

#content-inner.layout h1:hover,
#content-inner.layout h2:hover,
#content-inner.layout h3:hover,
#content-inner.layout h4:hover,
#content-inner.layout h5:hover,
#content-inner.layout h6:hover {
  color: var(--theme-color);
}

/* ================================ */
/* 评论输入提醒（Leonus） */
/* ================================ */
.el-input.el-input--small.el-input-group.el-input-group--prepend:nth-child(1)::before {
  content: "输入QQ号会自动获取昵称和头像";
}

.el-input.el-input--small.el-input-group.el-input-group--prepend:nth-child(2)::before {
  content: "收到回复将会发送到您的邮箱";
}

.el-input.el-input--small.el-input-group.el-input-group--prepend:nth-child(3)::before {
  content: "可以通过昵称访问您的网站";
}

.el-input.el-input--small.el-input-group.el-input-group--prepend::before {
  display: block;
  margin: 0 0 6px;
  font-size: 12px;
  line-height: 1.35;
  color: var(--font-color);
  opacity: 0.8;
}

/* ================================ */
/* TZY 同款页脚（适配当前站点） */
/* ================================ */
#footer-wrap {
  padding: 20px;
}

#ft {
  max-width: 1200px;
  margin: 0 auto 12px;
  display: flex;
  color: rgb(255 255 255 / 85%) !important;
  text-align: left;
  flex-wrap: wrap;
}

.ft-item-1,
.ft-item-2 {
  display: flex;
  height: 100%;
  padding: 2px 14px;
}

.ft-item-1 {
  flex-direction: column;
  flex: 2;
}

.ft-item-2 {
  flex: 1;
  flex-direction: column;
}

.t-top {
  display: flex;
}

.t-top .t-t-l {
  display: flex;
  flex-direction: column;
  flex: 1.4;
  margin-right: 10px;
}

.t-top .t-t-l .bg-ad {
  width: 85%;
  border-radius: 10px;
  padding: 8px 12px;
  background: rgba(255, 255, 255, 0.1);
  border: 1px solid rgba(255, 255, 255, 0.12);
}

.btn-xz-box {
  margin-top: 10px;
}

.btn-xz {
  display: block;
  background-color: var(--btn-bg);
  color: var(--btn-color);
  text-align: center;
  line-height: 2.4;
  margin: 8px 0;
}

.btn-xz:hover {
  text-decoration: none !important;
}

.btn-xz-box:hover .btn-xz {
  background-color: var(--text-bg-hover);
}

.t-top .t-t-r {
  display: flex;
  flex-direction: column;
  flex: 1;
}

.ft-links {
  padding: 0 14px;
  list-style: none;
  margin-top: 0 !important;
}

.ft-links li {
  margin-bottom: 8px;
}

.ft-links li a {
  display: inline-block !important;
  width: 50%;
}

.ft-links li a:hover {
  text-decoration: none !important;
  color: var(--theme-color) !important;
}

.ft-item-2 .ft-img-group {
  width: 100%;
}

.ft-t {
  font-size: 1.1rem;
  margin-bottom: 20px;
  line-height: 1;
  font-weight: 600;
}

.t-l-t {
  padding-left: 14px;
}

.ft-item-2 .ft-img-group .img-group-item {
  display: inline-block;
  width: 30%;
  margin-right: 3%;
  margin-bottom: 8px;
}

.ft-item-2 .ft-img-group .img-group-item a {
  display: inline-block;
  width: 100%;
  height: 100%;
}

.ft-item-2 .ft-img-group .img-group-item a img {
  width: 100%;
  max-height: 76px;
  min-height: 76px;
  object-fit: cover;
  border-radius: 10px;
  transition: 0.25s ease;
}

.ft-item-2 .ft-img-group .img-group-item a img:hover {
  border: 2px solid var(--theme-color);
  transform: translateY(-2px);
}

#footer-wrap a {
  border-radius: 30px;
}

#workboard {
  margin-top: 10px;
  text-align: center;
  color: var(--footer-muted-color) !important;
}

#workboard .boardsign {
  max-width: 260px;
}

#ghbdages {
  margin-top: 10px;
  text-align: center;
}

#ghbdages .github-badge {
  display: inline-block;
  margin: 5px;
}

#ghbdages .github-badge img {
  height: 22px;
}

#heartbeat {
  color: #ff4d4f;
  animation: iconAnimate 1s ease-in-out infinite;
}

@keyframes iconAnimate {
  0%,
  100% {
    transform: scale(1);
  }
  10%,
  30% {
    transform: scale(0.9);
  }
  20%,
  40%,
  60%,
  80% {
    transform: scale(1.1);
  }
  50%,
  70% {
    transform: scale(1.1);
  }
}

@media screen and (max-width: 768px) {
  .ft-item-1,
  .ft-item-2 {
    flex-basis: 100% !important;
  }

  .t-top .t-t-l .bg-ad {
    width: 100%;
  }
}

@media screen and (max-width: 576px) {
  .t-top {
    flex-wrap: wrap;
  }

  .t-top .t-t-l,
  .t-top .t-t-r {
    flex-basis: 100% !important;
  }

  .t-top .t-t-r {
    margin-top: 16px;
  }

  .ft-item-2 .ft-img-group .img-group-item {
    width: 48%;
    margin-right: 2%;
  }
}

/* ================================ */
/* 信息卡片头像状态 */
/* ================================ */
.card-widget .card-info-avatar {
  display: inline-block;
  position: relative;
}

.card-info-avatar .author-status-box {
  position: absolute;
  bottom: 0;
  left: calc(100% - 28px);
  width: 28px;
  height: 28px;
  border: 1px solid #d0d7de;
  border-radius: 2em;
  background-color: #f8f8f8f8;
  transition: 0.4s;
  overflow: hidden;
}

[data-theme="dark"] .card-info-avatar .author-status-box {
  background-color: #222222f2;
  border: 1px solid #5c6060;
}

.card-info-avatar .author-status-box .author-status {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 28px;
  padding: 0 5px;
}

.card-info-avatar .author-status-box:hover {
  width: 105px;
}

.card-info-avatar .author-status-box:hover .author-status .author-status-text {
  width: 105px;
  margin-left: 4px;
}

.card-info-avatar .author-status-box .author-status .author-status-text {
  width: 0;
  font-size: 12px;
  height: 100%;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  transition: 0.4s;
}

/* 已按需求移除信息卡悬浮彩带效果 */

Page._content:
/* 添加友链按钮 */
.addBtn {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 10px;
  margin: 18px auto 8px;
}

.addBtn button {
  transition: 0.2s;
  display: flex;
  align-items: center;
  color: var(--global-bg);
  padding: 12px 16px;
  border-radius: 40px;
  background: var(--search-result-title);
}

button {
  padding: 0;
  outline: 0;
  border: none;
  background: 0 0;
  cursor: pointer;
  touch-action: manipulation;
}

.fa-solid,
.fas {
  font-family: "Font Awesome 6 Free";
  font-weight: 900;
}

.addBtn i {
  font-size: 1.1rem;
  margin-right: 8px;
}

.addBtn button:hover {
  background: var(--theme-color);
  color: #fff;
