    result.textContent = message;
    result.style.color = isError ? '#e74c3c' : '';
  }

  function getTemplate(mode) {
    if (mode === 'bf') {
      return (
        '```yml\n' +
        '- name: \n' +
        '  link: \n' +
        '  avatar: \n' +
        '  descr: \n' +
        '  siteshot: \n' +
        '```'
      );
    }

    return (
      '站点名称：\n' +
      '站点地址：\n' +
