  }

  function animatePlanet(toDark) {
    var sun = document.getElementById('sun');
    var moon = document.getElementById('moon');
    if (!sun || !moon) return;

    if (toDark) {
      sun.style.opacity = '1';
      moon.style.opacity = '0';
      setTimeout(function () {
        sun.style.opacity = '0';
        moon.style.opacity = '1';
      }, ICON_SWAP_DELAY);
    } else {
      sun.style.opacity = '0';
      moon.style.opacity = '1';
      setTimeout(function () {
        sun.style.opacity = '1';
        moon.style.opacity = '0';
      }, ICON_SWAP_DELAY);
    }
  }

  window.switchNightMode = function () {
    var toDark = !isDark();

    createOverlay();
    animatePlanet(toDark);

    if (toDark) {
      applyDark();
      setTimeout(function () {
        notify('关灯啦🌙', '当前已成功切换至夜间模式！');
      }, OVERLAY_FADE_DELAY);
    } else {
      applyLight();
      setTimeout(function () {
        notify('开灯啦🌞', '当前已成功切换至白天模式！');
      }, OVERLAY_FADE_DELAY);
    }

    updateModeIcon();

    setTimeout(function () {
      var sky = document.querySelector('.Cuteen_DarkSky');
      if (!sky) return;
      sky.style.transition = 'opacity 3s';
      sky.style.opacity = '0';
      setTimeout(function () {
        sky.remove();
      }, OVERLAY_REMOVE_DELAY);
    }, OVERLAY_FADE_DELAY);

    safeThemeHooks();
  };

  function mountButton() {
    var oldBtn = document.getElementById('darkmode');
    if (!oldBtn) return;

    // 复制按钮节点以清空主题内置监听器，交由自定义动画控制。
    var btn = oldBtn.cloneNode(false);
    btn.id = 'darkmode';
    btn.type = 'button';
    btn.classList.add('icon-V');
    btn.title = oldBtn.title || '日间和夜间模式切换';
    btn.innerHTML = '<svg width="25" height="25" viewBox="0 0 1024 1024" aria-hidden="true"><use id="modeicon" xlink:href="#icon-moon"></use></svg>';

    oldBtn.parentNode.replaceChild(btn, oldBtn);
    btn.addEventListener('click', function (event) {
      event.preventDefault();
      window.switchNightMode();
    });

    updateModeIcon();
  }

  function init() {
    if (!document.body) return;
    ensureSprite();
    syncDarkClass();
    mountButton();
  }

  document.addEventListener('DOMContentLoaded', init);
  document.addEventListener('pjax:complete', init);
})();

